import type { Topic } from "./arcadeQuestions";

// ══════════════════════════════════════════════════
// SQL — OUTPUT GUESS (💻)
// ══════════════════════════════════════════════════
export const SQL_OUTPUT_TOPICS: Topic[] = [
  { id:"sql-out-basics", name:"Output: Basic Queries", icon:"💻", difficulty:"Easy", category:"Core", questions:[
    {id:1,question:"What does this return?\n\nSELECT 2 + 3;",options:["'2 + 3'","5","Error","NULL"],answer:"5",explanation:"SQL can evaluate expressions. SELECT 2 + 3 returns 5 as a single-row, single-column result."},
    {id:2,question:"What does DISTINCT return?\n\nSELECT DISTINCT city\nFROM users;\n-- Data: Delhi, Mumbai, Delhi, Chennai",options:["Delhi Mumbai Delhi Chennai","Delhi Mumbai Chennai","3 rows","Error"],answer:"Delhi Mumbai Chennai",explanation:"DISTINCT removes duplicates. Delhi appears once. Returns 3 unique cities."},
    {id:3,question:"What is the result?\n\nSELECT name\nFROM users\nWHERE age > 25\nORDER BY name ASC;",options:["All users","Users over 25, alphabetically","Users over 25, unsorted","Error"],answer:"Users over 25, alphabetically",explanation:"WHERE filters age > 25. ORDER BY name ASC sorts alphabetically. Both applied together."},
    {id:4,question:"What does this return?\n\nSELECT COUNT(*) FROM orders\nWHERE status = 'active';",options:["All orders","Active order rows","A single number — count of active orders","NULL"],answer:"A single number — count of active orders",explanation:"COUNT(*) returns single integer — number of rows matching WHERE condition."},
    {id:5,question:"What is the output?\n\nSELECT 10 / 3;",options:["3.33","3","3.0","Error"],answer:"3",explanation:"Integer division in most SQL databases. 10 / 3 = 3 (integer). Use 10.0 / 3 or CAST for decimal result."},
    {id:6,question:"What does NULL + 5 return?\n\nSELECT NULL + 5;",options:["5","NULL","Error","0"],answer:"NULL",explanation:"Any arithmetic with NULL returns NULL. NULL means unknown — unknown + 5 = still unknown."},
    {id:7,question:"What does this return?\n\nSELECT UPPER('hello world');",options:["hello world","Hello World","HELLO WORLD","Error"],answer:"HELLO WORLD",explanation:"UPPER() converts all characters to uppercase. LOWER() converts to lowercase."},
    {id:8,question:"What is the result?\n\nSELECT name, salary\nFROM employees\nORDER BY salary DESC\nLIMIT 1;",options:["Lowest paid","Highest paid employee","All employees","Error"],answer:"Highest paid employee",explanation:"ORDER BY salary DESC = highest first. LIMIT 1 = only first row. Returns the highest paid employee."},
    {id:9,question:"What does BETWEEN return?\n\nSELECT * FROM products\nWHERE price BETWEEN 10 AND 50;",options:["price > 10 AND price < 50","price >= 10 AND price <= 50","price = 10 OR price = 50","Error"],answer:"price >= 10 AND price <= 50",explanation:"BETWEEN is inclusive on both ends. BETWEEN 10 AND 50 = price >= 10 AND price <= 50."},
    {id:10,question:"What does LIKE '%ali%' match?\n\nSELECT * FROM users\nWHERE name LIKE '%ali%';",options:["Starts with ali","Ends with ali","Contains 'ali' anywhere","Exactly 'ali'"],answer:"Contains 'ali' anywhere",explanation:"% wildcard matches any sequence. '%ali%' = any chars + ali + any chars. Matches 'ali', 'Aaliyan', 'Somali'."},
  ]},
  { id:"sql-out-joins", name:"Output: JOINs", icon:"💻", difficulty:"Medium", category:"Core", questions:[
    {id:1,question:"How many rows does INNER JOIN return?\n\n-- users: Ali, Sara, Zara (3 rows)\n-- orders: Ali has 2, Sara has 1, Raza has 1\nSELECT u.name, o.total\nFROM users u\nINNER JOIN orders o ON u.id = o.userId;",options:["4 rows","3 rows","5 rows","7 rows"],answer:"3 rows",explanation:"INNER JOIN returns only matching rows. Ali(2) + Sara(1) = 3 matches. Zara (no orders) and Raza (no user) excluded."},
    {id:2,question:"How many rows does LEFT JOIN return?\n\n-- users: Ali, Sara, Zara (3 rows)\n-- orders: Ali has 2, Sara has 1\nSELECT u.name, o.total\nFROM users u\nLEFT JOIN orders o ON u.id = o.userId;",options:["3 rows","4 rows","2 rows","5 rows"],answer:"4 rows",explanation:"LEFT JOIN keeps all left (users) rows. Ali(2) + Sara(1) + Zara(null) = 4 rows. Zara has NULL for order columns."},
    {id:3,question:"What is Zara's total in LEFT JOIN result?\n\n-- Zara has no orders\nSELECT u.name, o.total\nFROM users u LEFT JOIN orders o ON u.id = o.userId;",options:["0","Error","NULL","Excluded"],answer:"NULL",explanation:"LEFT JOIN includes all left rows. For Zara with no matching order, right table columns are NULL."},
    {id:4,question:"What does CROSS JOIN produce?\n\n-- table A: 3 rows, table B: 4 rows\nSELECT * FROM A CROSS JOIN B;",options:["3 rows","4 rows","7 rows","12 rows"],answer:"12 rows",explanation:"CROSS JOIN = Cartesian product. Every row of A combined with every row of B. 3 × 4 = 12 rows."},
    {id:5,question:"What does this SELF JOIN return?\n\nSELECT e.name, m.name AS manager\nFROM employees e\nLEFT JOIN employees m ON e.managerId = m.id;",options:["Error — same table","All employees with their manager name (NULL if no manager)","Only employees with managers","Managers only"],answer:"All employees with their manager name (NULL if no manager)",explanation:"SELF JOIN: table joins itself. LEFT JOIN includes CEO (managerId NULL) with manager = NULL."},
    {id:6,question:"What is the result?\n\nSELECT COUNT(*)\nFROM users u\nINNER JOIN orders o ON u.id = o.userId\nWHERE o.total > 100;",options:["User count","Order count over 100","Number of users who have orders over 100","Error"],answer:"Number of users who have orders over 100",explanation:"JOIN then WHERE filters. COUNT(*) counts matched joined rows where order total > 100."},
    {id:7,question:"What does this return?\n\nSELECT u.name\nFROM users u\nLEFT JOIN orders o ON u.id = o.userId\nWHERE o.id IS NULL;",options:["Users with orders","Users without any orders","All users","Error"],answer:"Users without any orders",explanation:"LEFT JOIN + WHERE right.id IS NULL = rows with no match. Returns users who have placed no orders."},
    {id:8,question:"What does USING do?\n\nSELECT * FROM users\nJOIN orders USING (userId);",options:["Error","Same as ON users.userId = orders.userId","Joins on all columns","Joins on id only"],answer:"Same as ON users.userId = orders.userId",explanation:"USING(col) is shorthand when both tables have same column name. Produces one column instead of two."},
    {id:9,question:"How many columns does this return?\n\n-- users: id, name (2 cols)\n-- orders: id, userId, total (3 cols)\nSELECT * FROM users JOIN orders ON users.id = orders.userId;",options:["2","3","5","6"],answer:"5",explanation:"SELECT * returns all columns from both tables. users(2) + orders(3) = 5 columns in result."},
    {id:10,question:"What does this return?\n\nSELECT DISTINCT u.name\nFROM users u\nJOIN orders o ON u.id = o.userId;",options:["All users","Users with orders (each once)","Users with orders (with duplicates)","Order count"],answer:"Users with orders (each once)",explanation:"JOIN gets users with orders — may duplicate if multiple orders. DISTINCT removes duplicate names. Each user once."},
  ]},
  { id:"sql-out-aggregation", name:"Output: Aggregation", icon:"💻", difficulty:"Medium", category:"Core", questions:[
    {id:1,question:"What does GROUP BY return?\n\nSELECT dept, COUNT(*)\nFROM employees\nGROUP BY dept;\n-- Data: IT(3), HR(2), Sales(4)",options:["9 rows","3 rows — one per dept","All employee rows","Error"],answer:"3 rows — one per dept",explanation:"GROUP BY collapses rows into groups. One row per unique dept value. COUNT(*) counts per group."},
    {id:2,question:"What does HAVING filter?\n\nSELECT dept, COUNT(*) AS cnt\nFROM employees\nGROUP BY dept\nHAVING cnt > 2;",options:["Individual employees","Departments with more than 2 employees","All departments","Error"],answer:"Departments with more than 2 employees",explanation:"HAVING filters after GROUP BY. WHERE filters rows before grouping. HAVING filters groups after aggregation."},
    {id:3,question:"What is the output?\n\nSELECT AVG(salary)\nFROM employees;\n-- Salaries: 50000, 60000, 70000",options:["50000","60000","180000","Error"],answer:"60000",explanation:"AVG = sum / count. (50000 + 60000 + 70000) / 3 = 180000 / 3 = 60000."},
    {id:4,question:"What does COUNT(email) vs COUNT(*) return?\n\n-- 5 rows total, 2 have NULL email\nSELECT COUNT(*), COUNT(email) FROM users;",options:["5 and 5","5 and 3","3 and 5","3 and 3"],answer:"5 and 3",explanation:"COUNT(*) counts all rows including NULLs = 5. COUNT(col) counts non-NULL values = 3."},
    {id:5,question:"What does this return?\n\nSELECT dept, SUM(salary)\nFROM employees\nGROUP BY dept\nORDER BY SUM(salary) DESC;",options:["Error — can't ORDER BY aggregate","Total salary per dept, highest first","All salaries","Dept names only"],answer:"Total salary per dept, highest first",explanation:"Can ORDER BY aggregate functions. Returns salary total per department, sorted highest to lowest."},
    {id:6,question:"What does ROW_NUMBER() return?\n\nSELECT name, salary,\n  ROW_NUMBER() OVER (ORDER BY salary DESC) AS rank\nFROM employees;",options:["Salary rank with gaps","Sequential numbers 1,2,3...","Random numbers","Error"],answer:"Sequential numbers 1,2,3...",explanation:"ROW_NUMBER() assigns unique sequential integers. No ties — each row gets unique number regardless of equal salaries."},
    {id:7,question:"What is the difference?\n\n-- Salaries: 100, 90, 90, 80\nRANK() vs DENSE_RANK() for these values",options:["Same result","RANK: 1,2,2,4  DENSE_RANK: 1,2,2,3","RANK: 1,2,3,4  DENSE_RANK: 1,2,2,3","RANK: 1,2,2,3  DENSE_RANK: 1,2,2,4"],answer:"RANK: 1,2,2,4  DENSE_RANK: 1,2,2,3",explanation:"RANK skips numbers after ties (gap after rank 2). DENSE_RANK no gaps — next rank after tie is still consecutive."},
    {id:8,question:"What does PARTITION BY do here?\n\nSELECT name, dept,\n  AVG(salary) OVER (PARTITION BY dept) AS dept_avg\nFROM employees;",options:["Groups rows like GROUP BY","Returns avg per dept for each row without collapsing","Filters by dept","Error"],answer:"Returns avg per dept for each row without collapsing",explanation:"PARTITION BY in window function: calculates avg per dept but keeps all rows. Unlike GROUP BY which collapses."},
    {id:9,question:"What does this return?\n\nSELECT name,\n  LAG(salary) OVER (ORDER BY hire_date) AS prev_salary\nFROM employees;",options:["Next row salary","Previous row salary","Average salary","NULL for all"],answer:"Previous row salary",explanation:"LAG(col) returns value from previous row. First row has no previous — returns NULL. LEAD() gets next row."},
    {id:10,question:"What does SUM with OVER return?\n\nSELECT name, salary,\n  SUM(salary) OVER () AS total\nFROM employees;",options:["Running total","Same total salary for every row","Error","NULL"],answer:"Same total salary for every row",explanation:"SUM() OVER () with empty OVER = grand total applied to all rows. Each row shows its salary + total of all salaries."},
  ]},
  { id:"sql-out-subqueries", name:"Output: Subqueries & CTEs", icon:"💻", difficulty:"Medium", category:"Core", questions:[
    {id:1,question:"What does this subquery return?\n\nSELECT name FROM users\nWHERE id IN (\n  SELECT userId FROM orders\n  WHERE total > 100\n);",options:["Orders over 100","Users who have orders over 100","All users","Error"],answer:"Users who have orders over 100",explanation:"Subquery gets userIds with high orders. Outer query gets names for those users. IN matches against subquery results."},
    {id:2,question:"What does EXISTS return?\n\nSELECT name FROM users u\nWHERE EXISTS (\n  SELECT 1 FROM orders o\n  WHERE o.userId = u.id\n);",options:["Users without orders","Users with at least one order","All users","Error"],answer:"Users with at least one order",explanation:"EXISTS returns true if subquery returns any rows. Correlated subquery — checks per user. SELECT 1 is conventional."},
    {id:3,question:"What does this CTE return?\n\nWITH active_users AS (\n  SELECT * FROM users WHERE status = 'active'\n)\nSELECT COUNT(*) FROM active_users;",options:["All user count","Active user count","CTE definition","Error"],answer:"Active user count",explanation:"CTE defines temporary named result set. Main query uses it like a table. Returns count of active users."},
    {id:4,question:"What does scalar subquery return?\n\nSELECT name,\n  (SELECT COUNT(*) FROM orders WHERE userId = u.id) AS order_count\nFROM users u;",options:["Error — subquery in SELECT","Each user with their order count","Total order count","NULL"],answer:"Each user with their order count",explanation:"Scalar subquery in SELECT returns one value per row. Correlated — runs for each user. Returns order count per user."},
    {id:5,question:"What is the result?\n\nSELECT name FROM employees\nWHERE salary > ALL (\n  SELECT salary FROM employees WHERE dept = 'HR'\n);",options:["HR employees","Employees with salary higher than ALL HR salaries","Employees higher than any HR","Error"],answer:"Employees with salary higher than ALL HR salaries",explanation:"ALL: must be greater than every value in subquery. salary > ALL HR salaries = higher than highest HR salary."},
    {id:6,question:"What does NOT IN with NULL do?\n\nSELECT name FROM users\nWHERE id NOT IN (SELECT userId FROM banned WHERE userId IS NOT NULL);",options:["Works normally","Works correctly here — NULL excluded from subquery","Always returns empty","Error"],answer:"Works correctly here — NULL excluded from subquery",explanation:"NOT IN with NULL in subquery returns empty. But WHERE userId IS NOT NULL filters nulls out of subquery — safe."},
    {id:7,question:"What does this recursive CTE do?\n\nWITH RECURSIVE nums AS (\n  SELECT 1 AS n\n  UNION ALL\n  SELECT n + 1 FROM nums WHERE n < 5\n)\nSELECT * FROM nums;",options:["Error","Returns 1,2,3,4,5","Returns 1 only","Infinite loop"],answer:"Returns 1,2,3,4,5",explanation:"Recursive CTE: anchor (SELECT 1), recursive part adds 1 each time until n < 5 is false. Generates 1 through 5."},
    {id:8,question:"What does this derived table return?\n\nSELECT dept, avg_sal\nFROM (\n  SELECT dept, AVG(salary) AS avg_sal\n  FROM employees\n  GROUP BY dept\n) AS dept_avg\nWHERE avg_sal > 50000;",options:["All departments","Departments with average salary > 50000","All employees","Error"],answer:"Departments with average salary > 50000",explanation:"Derived table (subquery in FROM) acts as virtual table. WHERE filters on computed avg_sal — not possible directly with HAVING in same level."},
    {id:9,question:"What does UNION return?\n\nSELECT name FROM employees\nUNION\nSELECT name FROM contractors;",options:["All rows from both","Distinct names from both tables","Only matching names","Error"],answer:"Distinct names from both tables",explanation:"UNION combines results and removes duplicates. UNION ALL keeps all including duplicates. Columns must be compatible types."},
    {id:10,question:"What does this window function with CTE do?\n\nWITH ranked AS (\n  SELECT *, ROW_NUMBER() OVER\n  (PARTITION BY dept ORDER BY salary DESC) AS rn\n  FROM employees\n)\nSELECT * FROM ranked WHERE rn = 1;",options:["All employees ranked","Top earner per department","Employee rank 1 globally","Error"],answer:"Top earner per department",explanation:"ROW_NUMBER PARTITION BY dept — ranks within each dept. rn=1 = highest salary per dept. Classic top-N-per-group pattern."},
  ]},
  { id:"sql-out-transactions", name:"Output: Transactions & Constraints", icon:"💻", difficulty:"Hard", category:"Core", questions:[
    {id:1,question:"What happens here?\n\nBEGIN;\nINSERT INTO accounts VALUES (1, 1000);\nROLLBACK;",options:["Row inserted","Row inserted then removed","Error","Nothing"],answer:"Row inserted then removed",explanation:"ROLLBACK undoes all changes in transaction. INSERT ran but ROLLBACK reverts it — no net change to database."},
    {id:2,question:"What does COMMIT do?\n\nBEGIN;\nUPDATE accounts SET balance = balance - 100 WHERE id = 1;\nUPDATE accounts SET balance = balance + 100 WHERE id = 2;\nCOMMIT;",options:["Saves changes permanently","Reverts changes","Pauses transaction","Error"],answer:"Saves changes permanently",explanation:"COMMIT makes all transaction changes permanent and visible to other transactions. Cannot be rolled back after."},
    {id:3,question:"What does CHECK constraint do?\n\nCREATE TABLE products (\n  price DECIMAL CHECK (price > 0)\n);",options:["Creates index","Validates price > 0 on insert/update","Sets default","Creates trigger"],answer:"Validates price > 0 on insert/update",explanation:"CHECK constraint validates condition on insert/update. Error thrown if price <= 0. Database-level validation."},
    {id:4,question:"What happens with ON DELETE CASCADE?\n\n-- orders.userId REFERENCES users(id) ON DELETE CASCADE\nDELETE FROM users WHERE id = 1;",options:["Error — has orders","Deletes user only","Deletes user AND all their orders","Sets orders.userId to NULL"],answer:"Deletes user AND all their orders",explanation:"CASCADE: deleting parent automatically deletes all child rows. User deleted → all their orders deleted too."},
    {id:5,question:"What does SAVEPOINT do?\n\nBEGIN;\nINSERT INTO log VALUES ('step1');\nSAVEPOINT sp1;\nINSERT INTO log VALUES ('step2');\nROLLBACK TO sp1;\nCOMMIT;",options:["Both inserts saved","Only step1 saved","Neither saved","Error"],answer:"Only step1 saved",explanation:"ROLLBACK TO sp1 undoes changes after savepoint. step1 saved (before sp1), step2 rolled back. COMMIT saves step1."},
    {id:6,question:"What isolation level prevents dirty reads?\n\n-- Transaction reads uncommitted data from another transaction\n-- Which level prevents this?",options:["READ UNCOMMITTED","READ COMMITTED","REPEATABLE READ","SERIALIZABLE"],answer:"READ COMMITTED",explanation:"READ COMMITTED only reads committed data — prevents dirty reads. READ UNCOMMITTED allows dirty reads. Higher levels also prevent it."},
    {id:7,question:"What is a phantom read?\n\nT1: SELECT * FROM users WHERE age > 18  -- 10 rows\nT2: INSERT new user age 20, COMMIT\nT1: SELECT * FROM users WHERE age > 18  -- 11 rows",options:["Dirty read","Non-repeatable read","Phantom read","Lost update"],answer:"Phantom read",explanation:"Phantom read: same query returns different number of rows. T2 inserted new row T1 can now see. SERIALIZABLE prevents this."},
    {id:8,question:"What does FOREIGN KEY prevent?\n\nINSERT INTO orders (userId, total)\nVALUES (999, 100);\n-- No user with id=999 exists",options:["Nothing","Referential integrity error — userId must exist in users","Duplicate order","NULL error"],answer:"Referential integrity error — userId must exist in users",explanation:"FOREIGN KEY ensures referenced value exists in parent table. userId=999 doesn't exist in users → constraint violation error."},
    {id:9,question:"What does UNIQUE constraint allow?\n\nCREATE TABLE users (email VARCHAR(255) UNIQUE);\n-- Insert: ali@mail.com, sara@mail.com, ali@mail.com",options:["All 3 inserts","First 2 succeed, 3rd fails","All fail","Only 1 allowed"],answer:"First 2 succeed, 3rd fails",explanation:"UNIQUE allows one row per value. Third insert with duplicate ali@mail.com violates constraint — error thrown."},
    {id:10,question:"What does AUTOCOMMIT mean?\n\n-- MySQL default: autocommit = ON\nUPDATE users SET name = 'Ali' WHERE id = 1;\n-- No explicit BEGIN/COMMIT",options:["Changes not saved","Changes saved automatically after each statement","Transaction required","Error"],answer:"Changes saved automatically after each statement",explanation:"AUTOCOMMIT=ON: each statement is its own transaction, committed immediately. No BEGIN needed. Explicit BEGIN overrides this."},
  ]},
];

// ══════════════════════════════════════════════════
// SQL — BUG FINDER (🐛)
// ══════════════════════════════════════════════════
export const SQL_BUG_TOPICS: Topic[] = [
  { id:"sql-bug-queries", name:"Bug: Queries", icon:"🐛", difficulty:"Easy", category:"Core", questions:[
    {id:1,question:"Find the bug:\n\nSELECT name, dept, AVG(salary)\nFROM employees\nGROUP BY dept;",options:["No bug","name not in GROUP BY or aggregate — error","AVG wrong","Wrong table"],answer:"name not in GROUP BY or aggregate — error",explanation:"SELECT columns must be in GROUP BY or wrapped in aggregate. name not in GROUP BY — which name to show per dept? Add name to GROUP BY or remove it."},
    {id:2,question:"Find the bug:\n\nSELECT * FROM users\nWHERE name = NULL;",options:["No bug","NULL comparison must use IS NULL not = NULL","Wrong column","Wrong table"],answer:"NULL comparison must use IS NULL not = NULL",explanation:"= NULL always evaluates to UNKNOWN (never true). Use WHERE name IS NULL to find NULL values."},
    {id:3,question:"Find the bug:\n\nSELECT * FROM orders\nWHERE total > 100\nGROUP BY userId\nHAVING COUNT(*) > 2\nORDER BY total;",options:["No bug","ORDER BY total ambiguous — total not in GROUP BY or aggregate","Wrong HAVING","Wrong WHERE"],answer:"ORDER BY total ambiguous — total not in GROUP BY or aggregate",explanation:"After GROUP BY, only grouped columns and aggregates available. total not in GROUP BY — use ORDER BY SUM(total) or add to GROUP BY."},
    {id:4,question:"Find the bug:\n\nSELECT *\nFROM users\nHAVING age > 25;",options:["No bug","HAVING without GROUP BY — use WHERE for row filtering","Wrong column","Wrong table"],answer:"HAVING without GROUP BY — use WHERE for row filtering",explanation:"HAVING filters groups after GROUP BY. Without GROUP BY, use WHERE. HAVING age > 25 without GROUP BY is wrong — use WHERE age > 25."},
    {id:5,question:"Find the bug:\n\nSELECT TOP 10 * FROM products\nORDER BY price DESC;\n-- Running on PostgreSQL",options:["No bug","TOP is SQL Server syntax — use LIMIT in PostgreSQL","Wrong ORDER BY","Wrong column"],answer:"TOP is SQL Server syntax — use LIMIT in PostgreSQL",explanation:"TOP N is SQL Server/MS Access syntax. PostgreSQL uses LIMIT. MySQL also uses LIMIT. SELECT * FROM products ORDER BY price DESC LIMIT 10."},
    {id:6,question:"Find the bug:\n\nSELECT name FROM users\nWHERE name LIKE '%ali_';\n-- Trying to find names ending in 'ali'",options:["No bug","_ matches single char — use LIKE '%ali' not '%ali_'","Wrong LIKE","Wrong column"],answer:"_ matches single char — use LIKE '%ali' not '%ali_'",explanation:"_ is wildcard for exactly one character. '%ali_' = ends in 'ali' + one more char. To match ending in 'ali' use: LIKE '%ali'."},
    {id:7,question:"Find the bug:\n\nSELECT COUNT(DISTINCT *)\nFROM users;",options:["No bug","COUNT(DISTINCT *) is invalid — use COUNT(*) or COUNT(DISTINCT col)","Wrong function","Wrong syntax"],answer:"COUNT(DISTINCT *) is invalid — use COUNT(*) or COUNT(DISTINCT col)",explanation:"DISTINCT * is not valid inside COUNT. Use COUNT(*) for all rows or COUNT(DISTINCT column_name) for distinct values of one column."},
    {id:8,question:"Find the bug:\n\nSELECT name, salary\nFROM employees\nWHERE salary = MAX(salary);",options:["No bug","Aggregate functions not allowed in WHERE — use subquery or HAVING","Wrong operator","Wrong column"],answer:"Aggregate functions not allowed in WHERE — use subquery or HAVING",explanation:"WHERE can't use aggregates. Use: WHERE salary = (SELECT MAX(salary) FROM employees) — subquery gets max first."},
    {id:9,question:"Find the bug:\n\nSELECT *\nFROM users u\nJOIN orders o ON u.id = o.id;",options:["No bug","Wrong join condition — o.userId not o.id — will produce wrong results","Wrong alias","Wrong JOIN"],answer:"Wrong join condition — o.userId not o.id — will produce wrong results",explanation:"orders.id is the order's own PK. Should join on orders.userId = users.id. This joins wrong columns producing incorrect/cartesian results."},
    {id:10,question:"Find the bug:\n\nSELECT dept, COUNT(*)\nFROM employees\nGROUP BY dept\nORDER BY COUNT(*) DESC\nWHERE dept != 'HR';",options:["No bug","WHERE must come before GROUP BY — clause order wrong","Wrong ORDER BY","Wrong GROUP BY"],answer:"WHERE must come before GROUP BY — clause order wrong",explanation:"SQL clause order: SELECT → FROM → WHERE → GROUP BY → HAVING → ORDER BY. WHERE after ORDER BY is syntax error."},
  ]},
  { id:"sql-bug-joins", name:"Bug: JOINs & Subqueries", icon:"🐛", difficulty:"Medium", category:"Core", questions:[
    {id:1,question:"Find the bug:\n\nSELECT u.name, COUNT(o.id)\nFROM users u\nJOIN orders o ON u.id = o.userId\nGROUP BY u.name;\n-- Missing users with 0 orders",options:["No bug","INNER JOIN excludes users with no orders — use LEFT JOIN","Wrong GROUP BY","Wrong COUNT"],answer:"INNER JOIN excludes users with no orders — use LEFT JOIN",explanation:"INNER JOIN only returns rows with matches. Users with 0 orders not matched. Use LEFT JOIN to include all users, COUNT(o.id) returns 0 for no orders."},
    {id:2,question:"Find the bug:\n\nSELECT *\nFROM users\nWHERE id NOT IN (\n  SELECT userId FROM orders\n);",options:["No bug","If any userId in orders is NULL, NOT IN returns empty result","Wrong subquery","Wrong IN"],answer:"If any userId in orders is NULL, NOT IN returns empty result",explanation:"NOT IN with NULL in subquery: x NOT IN (1, 2, NULL) → x != 1 AND x != 2 AND x != NULL → always UNKNOWN → no rows. Add WHERE userId IS NOT NULL."},
    {id:3,question:"Find the bug:\n\nSELECT u.name\nFROM users u, orders o\nWHERE u.id = o.userId\nAND o.total > 100;",options:["No bug — implicit join works","Old syntax but works — no bug, though explicit JOIN preferred","Error — comma syntax","Wrong WHERE"],answer:"Old syntax but works — no bug, though explicit JOIN preferred",explanation:"Comma syntax (implicit cross join with WHERE filter) is old but valid SQL. Equivalent to explicit INNER JOIN. No bug — just outdated style."},
    {id:4,question:"Find the bug:\n\nSELECT name FROM users\nWHERE salary > ANY (\n  SELECT salary FROM managers\n);\n-- Trying to find users earning more than ALL managers",options:["No bug","ANY returns true if greater than at least one — use ALL for all managers","Wrong subquery","Wrong operator"],answer:"ANY returns true if greater than at least one — use ALL for all managers",explanation:"ANY = greater than at least one value. ALL = greater than every value. To find users earning more than ALL managers, use > ALL."},
    {id:5,question:"Find the bug:\n\nWITH top_earners AS (\n  SELECT * FROM employees\n  ORDER BY salary DESC\n  LIMIT 10\n)\nSELECT * FROM top_earners\nWHERE dept = 'IT';",options:["No bug","ORDER BY in CTE not guaranteed in some DBs — sort in outer query","LIMIT wrong","Wrong CTE"],answer:"No bug",explanation:"This is valid SQL. CTE with ORDER BY + LIMIT finds top 10 earners, then filters by IT. May have portability issues in some databases but logically correct."},
    {id:6,question:"Find the bug:\n\nSELECT e.name, d.name\nFROM employees e\nFULL OUTER JOIN departments d ON e.deptId = d.id\nWHERE e.name IS NOT NULL\nAND d.name IS NOT NULL;",options:["No bug","WHERE filters nulls — defeats purpose of FULL OUTER JOIN (converts to INNER JOIN)","Wrong JOIN","Wrong WHERE"],answer:"WHERE filters nulls — defeats purpose of FULL OUTER JOIN (converts to INNER JOIN)",explanation:"FULL OUTER JOIN includes non-matching rows with NULLs. Filtering IS NOT NULL removes those — result same as INNER JOIN."},
    {id:7,question:"Find the bug:\n\nSELECT name FROM employees\nUNION\nSELECT name, dept FROM departments;",options:["No bug","UNION requires same number of columns and compatible types","Wrong UNION","Wrong SELECT"],answer:"UNION requires same number of columns and compatible types",explanation:"UNION: both queries must have same column count and compatible types. First has 1 column, second has 2 — mismatch error."},
    {id:8,question:"Find the bug:\n\nSELECT *\nFROM orders\nWHERE createdAt BETWEEN '2024-01-01' AND '2024-01-31';\n-- Missing orders from Jan 31",options:["No bug","BETWEEN with datetime — '2024-01-31' is midnight, misses rest of Jan 31","Wrong dates","Wrong BETWEEN"],answer:"BETWEEN with datetime — '2024-01-31' is midnight, misses rest of Jan 31",explanation:"'2024-01-31' = '2024-01-31 00:00:00'. Orders after midnight Jan 31 excluded. Use: AND '2024-02-01' or BETWEEN '2024-01-01' AND '2024-01-31 23:59:59'."},
    {id:9,question:"Find the bug:\n\nSELECT d.name, AVG(e.salary)\nFROM departments d\nLEFT JOIN employees e ON d.id = e.deptId\nGROUP BY d.name\nHAVING AVG(e.salary) > 50000;",options:["No bug","Empty departments excluded by HAVING AVG > 50000 — AVG(NULL) = NULL","Wrong JOIN","Wrong HAVING"],answer:"No bug",explanation:"HAVING AVG > 50000 naturally excludes empty departments (AVG returns NULL for no rows, NULL > 50000 = false). This is the intended behavior. No bug."},
    {id:10,question:"Find the bug:\n\nSELECT name\nFROM users\nWHERE EXISTS (\n  SELECT * FROM orders\n  WHERE total > 100\n);",options:["No bug","Non-correlated EXISTS — returns all users if ANY order > 100 exists, else none","Wrong EXISTS","Wrong subquery"],answer:"Non-correlated EXISTS — returns all users if ANY order > 100 exists, else none",explanation:"Subquery not correlated to outer query (no u.id reference). EXISTS true for all rows or none. Fix: WHERE o.userId = u.id."},
  ]},
  { id:"sql-bug-schema", name:"Bug: Schema & Constraints", icon:"🐛", difficulty:"Medium", category:"Core", questions:[
    {id:1,question:"Find the bug:\n\nCREATE TABLE orders (\n  id INT PRIMARY KEY,\n  userId INT,\n  total DECIMAL\n);\nCREATE TABLE users (\n  id INT PRIMARY KEY,\n  name VARCHAR(100)\n);",options:["No bug","Foreign key missing — userId should reference users(id)","Wrong types","Wrong order"],answer:"Foreign key missing — userId should reference users(id)",explanation:"userId references users but no FOREIGN KEY constraint declared. Add: FOREIGN KEY (userId) REFERENCES users(id) for referential integrity."},
    {id:2,question:"Find the bug:\n\nCREATE TABLE products (\n  id INT,\n  name VARCHAR(100) NOT NULL,\n  price DECIMAL DEFAULT -1\n);",options:["No bug","No PRIMARY KEY — id not constrained, allows duplicates and NULLs","Wrong default","Wrong type"],answer:"No PRIMARY KEY — id not constrained, allows duplicates and NULLs",explanation:"id has no PRIMARY KEY or UNIQUE+NOT NULL constraints. Multiple rows can have same id or NULL id. Add PRIMARY KEY or AUTO_INCREMENT."},
    {id:3,question:"Find the bug:\n\nALTER TABLE users\nADD COLUMN age INT NOT NULL;",options:["No bug","Adding NOT NULL column to existing table with data — error or all NULLs","Wrong ALTER","Wrong type"],answer:"Adding NOT NULL column to existing table with data — error or all NULLs",explanation:"Adding NOT NULL column to table with existing rows — existing rows have no value. Add DEFAULT: ADD COLUMN age INT NOT NULL DEFAULT 0."},
    {id:4,question:"Find the bug:\n\nCREATE TABLE employees (\n  id INT PRIMARY KEY,\n  managerId INT REFERENCES employees(id) ON DELETE CASCADE\n);",options:["No bug","ON DELETE CASCADE on self-reference — deleting manager cascades to employees then their reports, potentially deleting whole tree","Wrong reference","Wrong CASCADE"],answer:"No bug",explanation:"Self-referential foreign key with CASCADE is valid and intentional for hierarchical data. Deleting manager deletes reports recursively. This may be intentional. No bug per se."},
    {id:5,question:"Find the bug:\n\nCREATE INDEX idx_name ON users(name);\nCREATE INDEX idx_name ON users(email);",options:["No bug","Duplicate index name idx_name — second CREATE fails","Wrong index","Wrong table"],answer:"Duplicate index name idx_name — second CREATE fails",explanation:"Index names must be unique within a table (or schema in some DBs). Two indexes named idx_name — second fails. Use idx_email for second."},
    {id:6,question:"Find the bug:\n\nSELECT * FROM users\nWHERE UPPER(email) = 'ALI@MAIL.COM'\n-- Has index on email column",options:["No bug","Function on indexed column — UPPER() prevents index use — slow","Wrong function","Wrong comparison"],answer:"Function on indexed column — UPPER() prevents index use — slow",explanation:"Wrapping indexed column in function prevents index use. Store emails lowercase or use functional index: CREATE INDEX ON users(UPPER(email))."},
    {id:7,question:"Find the bug:\n\nCREATE TABLE logs (\n  id INT AUTO_INCREMENT PRIMARY KEY,\n  message TEXT,\n  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n-- Add index for time-based queries:\nCREATE INDEX idx_all ON logs(id, message, created_at);",options:["No bug","Over-indexing — index on TEXT column and all columns — wastes space, slows writes","Wrong index","Wrong table"],answer:"Over-indexing — index on TEXT column and all columns — wastes space, slows writes",explanation:"Indexing TEXT column is expensive. Index on all columns rarely helps — query optimizer prefers targeted indexes. Create: idx_created ON logs(created_at) instead."},
    {id:8,question:"Find the bug:\n\nCREATE TABLE sessions (\n  token VARCHAR(255) PRIMARY KEY,\n  userId INT,\n  data JSON,\n  expiresAt TIMESTAMP\n);\n-- Sessions expire after 1 hour, table grows forever",options:["No bug","No cleanup mechanism — table grows indefinitely — add scheduled cleanup or TTL","Wrong type","Wrong PRIMARY KEY"],answer:"No cleanup mechanism — table grows indefinitely — add scheduled cleanup or TTL",explanation:"Sessions expire but no deletion mechanism. Table grows forever. Add scheduled DELETE WHERE expiresAt < NOW() or use Redis with built-in TTL."},
    {id:9,question:"Find the bug:\n\nINSERT INTO users (id, name)\nVALUES (1, 'Ali'),\n       (2, 'Sara'),\n       (1, 'Zara'); -- duplicate id",options:["No bug","Third row violates PRIMARY KEY — entire INSERT fails or partial insert depending on DB","Error in syntax","Wrong VALUES"],answer:"Third row violates PRIMARY KEY — entire INSERT fails or partial insert depending on DB",explanation:"id=1 already exists. PRIMARY KEY violation. In MySQL with default settings, entire INSERT fails. Use INSERT IGNORE or ON CONFLICT DO NOTHING."},
    {id:10,question:"Find the bug:\n\nCREATE TABLE orders (\n  id INT PRIMARY KEY,\n  userId INT NOT NULL,\n  FOREIGN KEY (userId) REFERENCES users(id)\n    ON DELETE RESTRICT\n    ON UPDATE CASCADE\n);\nUPDATE users SET id = 999 WHERE id = 1;",options:["No bug","ON UPDATE CASCADE: userId in orders updates to 999 automatically — may be unintended","Wrong CASCADE","Error"],answer:"No bug",explanation:"ON UPDATE CASCADE on FK is valid and intentional here — when user id changes, all their orders userId updates too. This is by design. No bug."},
  ]},
  { id:"sql-bug-performance", name:"Bug: Performance & Transactions", icon:"🐛", difficulty:"Hard", category:"Core", questions:[
    {id:1,question:"Find the bug:\n\nSELECT * FROM orders\nWHERE YEAR(created_at) = 2024;",options:["No bug","YEAR() on indexed column prevents index use — use range query instead","Wrong function","Wrong year"],answer:"YEAR() on indexed column prevents index use — use range query instead",explanation:"Functions on indexed columns prevent index use. Use: WHERE created_at >= '2024-01-01' AND created_at < '2025-01-01' for index scan."},
    {id:2,question:"Find the bug:\n\nSELECT u.*, o.*, p.*\nFROM users u\nJOIN orders o ON u.id = o.userId\nJOIN products p ON o.productId = p.id\nWHERE u.id = 1;",options:["No bug","SELECT * with multiple JOINs — fetches all columns including duplicates, wastes bandwidth","Wrong JOIN","Wrong WHERE"],answer:"SELECT * with multiple JOINs — fetches all columns including duplicates, wastes bandwidth",explanation:"SELECT * fetches everything. With 3 tables joined, returns all columns including duplicate ids. Specify needed columns: SELECT u.name, o.total, p.name."},
    {id:3,question:"Find the bug:\n\n-- N+1 query problem:\nSELECT * FROM users; -- 1 query\n-- Then for each user:\nSELECT * FROM orders WHERE userId = ?; -- N queries",options:["No bug","N+1 problem — 1 + N queries — use JOIN or IN instead","Wrong queries","Loop issue"],answer:"N+1 problem — 1 + N queries — use JOIN or IN instead",explanation:"100 users = 101 queries. Fix: SELECT u.*, o.* FROM users u LEFT JOIN orders o ON u.id = o.userId — single query gets everything."},
    {id:4,question:"Find the bug:\n\nBEGIN;\nSELECT balance FROM accounts WHERE id = 1; -- reads 1000\n-- Application processes for 5 seconds\nUPDATE accounts SET balance = balance - 100 WHERE id = 1;\nCOMMIT;",options:["No bug","Lost update — another transaction may change balance in 5 seconds","Wrong transaction","Wrong UPDATE"],answer:"Lost update — another transaction may change balance in 5 seconds",explanation:"Between SELECT and UPDATE, another transaction may change balance. Use SELECT ... FOR UPDATE to lock row, or use optimistic locking with version column."},
    {id:5,question:"Find the bug:\n\nSELECT COUNT(*) FROM large_table;\n-- large_table has 100 million rows",options:["No bug","COUNT(*) without WHERE scans entire table — very slow for huge tables","Wrong function","Wrong table"],answer:"No bug — but use estimatedDocumentCount for approximate",explanation:"COUNT(*) is valid but can be slow on huge tables. For approximation use database-specific fast count methods. For exact count with filter, it's necessary. No syntax bug."},
    {id:6,question:"Find the bug:\n\nDELETE FROM logs WHERE created_at < '2023-01-01';\n-- logs table has 50 million old rows",options:["No bug","Deletes millions of rows in one transaction — locks table, fills transaction log","Wrong DELETE","Wrong date"],answer:"Deletes millions of rows in one transaction — locks table, fills transaction log",explanation:"Bulk delete locks table and fills transaction log. Use batched deletes: DELETE TOP(1000) WHERE ... in a loop with small commits."},
    {id:7,question:"Find the bug:\n\nSELECT *\nFROM users\nORDER BY RAND()\nLIMIT 10;",options:["No bug","ORDER BY RAND() scans entire table for each row — extremely slow on large tables","Wrong RAND","Wrong LIMIT"],answer:"ORDER BY RAND() scans entire table for each row — extremely slow on large tables",explanation:"RAND() per row = full table scan then sort. Very slow. Alternative: SELECT * FROM users WHERE id >= RAND() * (SELECT MAX(id) FROM users) LIMIT 10."},
    {id:8,question:"Find the bug:\n\nCREATE TABLE events (\n  id INT AUTO_INCREMENT PRIMARY KEY,\n  type VARCHAR(50),\n  data JSON,\n  created_at TIMESTAMP\n);\n-- Query: SELECT * WHERE type = 'login' ORDER BY created_at\n-- No indexes added",options:["No bug","No index on type or created_at — full table scan for every query","Wrong schema","Wrong types"],answer:"No index on type or created_at — full table scan for every query",explanation:"Queries on type and created_at without indexes = full table scan. Add: CREATE INDEX idx_type_created ON events(type, created_at)."},
    {id:9,question:"Find the bug:\n\nBEGIN;\nUPDATE accounts SET balance = balance - 500 WHERE id = 1;\n-- Application crashes here\n-- No ROLLBACK executed",options:["No bug","Transaction auto-rolls back on connection close — this is actually handled","Lost data","Data corruption"],answer:"Transaction auto-rolls back on connection close — this is actually handled",explanation:"Most databases automatically rollback uncommitted transactions when connection closes/crashes. ACID durability ensures incomplete transactions are rolled back. No data corruption."},
    {id:10,question:"Find the bug:\n\nSELECT *\nFROM products p\nWHERE p.category_id IN (\n  SELECT id FROM categories\n  WHERE parent_id IN (\n    SELECT id FROM categories WHERE name = 'Electronics'\n  )\n);",options:["No bug","Deeply nested subqueries — hard to read and potentially slow — use JOINs or CTEs","Wrong IN","Wrong subquery"],answer:"No bug",explanation:"Nested subqueries are valid SQL. May be less readable and potentially less optimized than JOINs, but optimizer often handles it. No syntax bug — style concern only."},
  ]},
];

