// SQL — FILL IN THE BLANK (⬜)
// ══════════════════════════════════════════════════
export const SQL_FILL_TOPICS: Topic[] = [
  { id:"sql-fill-basics", name:"Fill: Basic SQL", icon:"⬜", difficulty:"Easy", category:"Core", questions:[
    {id:1,question:"Complete to get all columns:\n\n_____ * FROM users;",options:["GET","FETCH","SELECT","QUERY"],answer:"SELECT",explanation:"SELECT is DML command to retrieve data. SELECT * = all columns. SELECT col1, col2 = specific columns."},
    {id:2,question:"Complete to filter rows:\n\nSELECT * FROM users\n_____ age > 18;",options:["HAVING","FILTER","WHERE","CONDITION"],answer:"WHERE",explanation:"WHERE filters rows before grouping. HAVING filters after GROUP BY. WHERE age > 18 returns users over 18."},
    {id:3,question:"Complete to sort results:\n\nSELECT * FROM products\nORDER BY price _____;",options:["DESCENDING","DOWN","DESC","HIGH"],answer:"DESC",explanation:"DESC = descending (highest first). ASC = ascending (lowest first). Default is ASC if not specified."},
    {id:4,question:"Complete to count rows:\n\nSELECT _____(*) FROM orders;",options:["COUNT","SUM","TOTAL","NUM"],answer:"COUNT",explanation:"COUNT(*) counts all rows including NULLs. COUNT(col) counts non-NULL values. SUM adds numeric values."},
    {id:5,question:"Complete to find unique values:\n\nSELECT _____ city FROM users;",options:["UNIQUE","DISTINCT","DIFFERENT","NODUPE"],answer:"DISTINCT",explanation:"DISTINCT removes duplicate rows from result. SELECT DISTINCT city returns each city once."},
    {id:6,question:"Complete to limit results:\n\nSELECT * FROM users\nORDER BY created_at DESC\n_____ 10;",options:["TOP","TAKE","LIMIT","FIRST"],answer:"LIMIT",explanation:"LIMIT n restricts rows returned. MySQL/PostgreSQL use LIMIT. SQL Server uses TOP. Oracle uses ROWNUM or FETCH FIRST."},
    {id:7,question:"Complete to check for NULL:\n\nSELECT * FROM users\nWHERE phone _____ NULL;",options:["= ","IS ","== ","EQUALS "],answer:"IS ",explanation:"NULL comparison needs IS NULL or IS NOT NULL. = NULL always returns UNKNOWN — never matches any row."},
    {id:8,question:"Complete the GROUP BY:\n\nSELECT dept, COUNT(*)\nFROM employees\n_____ _____ dept;",options:["ORDER BY","GROUP BY","SORT BY","PARTITION BY"],answer:"GROUP BY",explanation:"GROUP BY groups rows with same values. Aggregate functions (COUNT, SUM, AVG) operate per group."},
    {id:9,question:"Complete to filter groups:\n\nSELECT dept, AVG(salary)\nFROM employees\nGROUP BY dept\n_____ AVG(salary) > 50000;",options:["WHERE","FILTER","HAVING","CONDITION"],answer:"HAVING",explanation:"HAVING filters after GROUP BY. WHERE filters before grouping. HAVING can use aggregate functions, WHERE cannot."},
    {id:10,question:"Complete to match pattern:\n\nSELECT * FROM users\nWHERE name _____ 'Ali%';",options:["MATCHES","LIKE","CONTAINS","SIMILAR"],answer:"LIKE",explanation:"LIKE pattern matching: % = any chars, _ = single char. 'Ali%' matches names starting with 'Ali'."},
  ]},
  { id:"sql-fill-joins", name:"Fill: JOINs & Aggregation", icon:"⬜", difficulty:"Medium", category:"Core", questions:[
    {id:1,question:"Complete INNER JOIN:\n\nSELECT u.name, o.total\nFROM users u\n_____ _____ orders o ON u.id = o.userId;",options:["INNER JOIN","JOIN INNER","MATCH JOIN","CONNECT JOIN"],answer:"INNER JOIN",explanation:"INNER JOIN returns only matching rows from both tables. Same as JOIN (default). Excludes non-matching rows."},
    {id:2,question:"Complete to include all left rows:\n\nSELECT u.name, COUNT(o.id)\nFROM users u\n_____ JOIN orders o ON u.id = o.userId\nGROUP BY u.name;",options:["INNER","LEFT","RIGHT","FULL"],answer:"LEFT",explanation:"LEFT JOIN includes all rows from left (users) table. Users with no orders get NULL for order columns, COUNT = 0."},
    {id:3,question:"Complete the self join:\n\nSELECT e.name, m.name AS manager\nFROM employees e\nLEFT JOIN employees _____ ON e.managerId = m.id;",options:["AS m","e","m","emp m"],answer:"m",explanation:"Self join: same table with different alias. employees m is second reference to employees table for manager lookup."},
    {id:4,question:"Complete to get total per group:\n\nSELECT userId, _____(amount) AS total\nFROM orders\nGROUP BY userId;",options:["COUNT","AVG","SUM","MAX"],answer:"SUM",explanation:"SUM(amount) adds up all amounts per userId group. Returns total order amount per user."},
    {id:5,question:"Complete the window function:\n\nSELECT name, salary,\n  RANK() _____ (ORDER BY salary DESC) AS rnk\nFROM employees;",options:["PARTITION","OVER","BY","WITHIN"],answer:"OVER",explanation:"OVER clause defines window for window functions. OVER (ORDER BY salary DESC) ranks by salary descending."},
    {id:6,question:"Complete to partition window:\n\nSELECT name, dept, salary,\n  AVG(salary) OVER (_____ _____ dept) AS dept_avg\nFROM employees;",options:["GROUP BY","PARTITION BY","ORDER BY","FILTER BY"],answer:"PARTITION BY",explanation:"PARTITION BY in window function divides rows into groups. AVG calculated per partition (dept) without collapsing rows."},
    {id:7,question:"Complete to combine results:\n\nSELECT name FROM employees\n_____\nSELECT name FROM contractors;",options:["JOIN","UNION","MERGE","COMBINE"],answer:"UNION",explanation:"UNION combines results of two SELECT statements. Removes duplicates. UNION ALL keeps duplicates. Same column count required."},
    {id:8,question:"Complete to get previous row value:\n\nSELECT name, salary,\n  _____(salary) OVER (ORDER BY hire_date) AS prev_salary\nFROM employees;",options:["PREV","LEAD","LAG","BEFORE"],answer:"LAG",explanation:"LAG(col) returns value from previous row. LAG(col, 2) = 2 rows back. LEAD(col) = next row. NULL for first/last row."},
    {id:9,question:"Complete running total:\n\nSELECT date, amount,\n  SUM(amount) OVER (\n    ORDER BY date\n    ROWS BETWEEN UNBOUNDED PRECEDING AND _____\n  ) AS running_total\nFROM sales;",options:["UNBOUNDED FOLLOWING","CURRENT ROW","1 FOLLOWING","0 PRECEDING"],answer:"CURRENT ROW",explanation:"ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW = from start to current row = running total."},
    {id:10,question:"Complete to find top earner per dept:\n\nWITH ranked AS (\n  SELECT *, ROW_NUMBER() OVER\n  (PARTITION BY dept ORDER BY salary DESC) AS rn\n  FROM employees\n)\nSELECT * FROM ranked WHERE rn = _____;",options:["0","1","MAX","TOP"],answer:"1",explanation:"ROW_NUMBER() per partition starts at 1. rn=1 = first row per partition = highest salary per dept."},
  ]},
  { id:"sql-fill-advanced", name:"Fill: Advanced SQL", icon:"⬜", difficulty:"Hard", category:"Core", questions:[
    {id:1,question:"Complete the CTE:\n\n_____ active_users AS (\n  SELECT * FROM users WHERE status = 'active'\n)\nSELECT COUNT(*) FROM active_users;",options:["CREATE","DEFINE","WITH","TEMP"],answer:"WITH",explanation:"WITH clause creates CTE (Common Table Expression). Named temporary result set used in main query. Improves readability."},
    {id:2,question:"Complete recursive CTE:\n\nWITH _____ hierarchy AS (\n  SELECT id, name, managerId, 1 AS level\n  FROM employees WHERE managerId IS NULL\n  UNION ALL\n  SELECT e.id, e.name, e.managerId, h.level + 1\n  FROM employees e JOIN hierarchy h ON e.managerId = h.id\n)\nSELECT * FROM hierarchy;",options:["LOOP","ITERATE","RECURSIVE","TREE"],answer:"RECURSIVE",explanation:"RECURSIVE keyword enables recursive CTEs. Anchor member + recursive member. Traverses hierarchical data like org charts."},
    {id:3,question:"Complete CASE expression:\n\nSELECT name,\n  _____ WHEN age < 18 THEN 'Minor'\n        WHEN age < 60 THEN 'Adult'\n        ELSE 'Senior'\n  END AS age_group\nFROM users;",options:["IF","IIF","CASE","SWITCH"],answer:"CASE",explanation:"CASE WHEN ... THEN ... ELSE ... END = conditional expression. SQL's version of if/else. Can be in SELECT, WHERE, ORDER BY."},
    {id:4,question:"Complete to handle NULL:\n\nSELECT name,\n  _____(phone, mobile, 'N/A') AS contact\nFROM users;",options:["ISNULL","NVL","COALESCE","IFNULL"],answer:"COALESCE",explanation:"COALESCE returns first non-NULL value. Standard SQL. ISNULL (SQL Server), NVL (Oracle), IFNULL (MySQL) — DB-specific alternatives."},
    {id:5,question:"Complete to cast type:\n\nSELECT name,\n  _____(salary AS VARCHAR(20))\nFROM employees;",options:["CONVERT","PARSE","CAST","TO_CHAR"],answer:"CAST",explanation:"CAST(value AS type) converts data type. Standard SQL. CONVERT is SQL Server specific. Both CAST and CONVERT work in most DBs."},
    {id:6,question:"Complete to create view:\n\n_____ VIEW active_users AS\nSELECT * FROM users WHERE status = 'active';",options:["MAKE","BUILD","CREATE","DEFINE"],answer:"CREATE",explanation:"CREATE VIEW name AS SELECT ... creates virtual table. Stored query, not data. Query view like a table."},
    {id:7,question:"Complete the transaction:\n\n_____;\nUPDATE accounts SET balance = balance - 100 WHERE id = 1;\nUPDATE accounts SET balance = balance + 100 WHERE id = 2;\n_____;\n",options:["START / END","BEGIN / COMMIT","OPEN / CLOSE","INIT / SAVE"],answer:"BEGIN / COMMIT",explanation:"BEGIN starts transaction. COMMIT saves all changes permanently. ROLLBACK undoes changes. ACID atomicity guarantee."},
    {id:8,question:"Complete to add column:\n\n_____ TABLE users\n_____ COLUMN phone VARCHAR(20);",options:["MODIFY / ADD","ALTER / ADD","CHANGE / INSERT","UPDATE / ADD"],answer:"ALTER / ADD",explanation:"ALTER TABLE modifies table structure. ADD COLUMN adds new column. DROP COLUMN removes. MODIFY/ALTER COLUMN changes type."},
    {id:9,question:"Complete to concatenate strings:\n\nSELECT _____(first_name, ' ', last_name) AS full_name\nFROM users;\n-- Standard SQL",options:["JOIN","MERGE","CONCAT","APPEND"],answer:"CONCAT",explanation:"CONCAT(str1, str2, ...) joins strings. Standard in MySQL/PostgreSQL. SQL Server uses + or CONCAT. PostgreSQL also allows ||."},
    {id:10,question:"Complete EXISTS subquery:\n\nSELECT name FROM users u\nWHERE _____ (\n  SELECT 1 FROM orders o\n  WHERE o.userId = u.id\n  AND o.total > 100\n);",options:["IN","ANY","EXISTS","CONTAINS"],answer:"EXISTS",explanation:"EXISTS returns true if subquery returns any rows. Correlated subquery runs per row. More efficient than IN for existence checks."},
  ]},
  { id:"sql-fill-schema", name:"Fill: Schema & Constraints", icon:"⬜", difficulty:"Medium", category:"Core", questions:[
    {id:1,question:"Complete to create table:\n\n_____ _____ users (\n  id INT PRIMARY KEY,\n  name VARCHAR(100) NOT NULL\n);",options:["MAKE TABLE","CREATE TABLE","NEW TABLE","BUILD TABLE"],answer:"CREATE TABLE",explanation:"CREATE TABLE defines new table with columns and constraints. DDL statement — affects schema not data."},
    {id:2,question:"Complete primary key:\n\nCREATE TABLE products (\n  id INT _____ _____,\n  name VARCHAR(100)\n);",options:["PRIMARY KEY","UNIQUE KEY","NOT NULL KEY","INDEX KEY"],answer:"PRIMARY KEY",explanation:"PRIMARY KEY = UNIQUE + NOT NULL. Uniquely identifies each row. One per table. Often AUTO_INCREMENT or SERIAL."},
    {id:3,question:"Complete foreign key:\n\nCREATE TABLE orders (\n  id INT PRIMARY KEY,\n  userId INT,\n  _____ _____ (userId) REFERENCES users(id)\n);",options:["FOREIGN KEY","REFERENCE KEY","LINK KEY","JOIN KEY"],answer:"FOREIGN KEY",explanation:"FOREIGN KEY enforces referential integrity. userId must exist in users.id. Prevents orphaned records."},
    {id:4,question:"Complete auto increment:\n\nCREATE TABLE users (\n  id INT _____ _____ PRIMARY KEY,\n  name VARCHAR(100)\n);\n-- MySQL syntax",options:["AUTO_INCREMENT","AUTO INCREMENT","AUTOINCREMENT","SERIAL"],answer:"AUTO_INCREMENT",explanation:"AUTO_INCREMENT (MySQL) auto-generates sequential IDs. PostgreSQL uses SERIAL or GENERATED ALWAYS AS IDENTITY."},
    {id:5,question:"Complete to add index:\n\nCREATE _____ idx_email ON users(email);",options:["INDEX","KEY","SEARCH","LOOKUP"],answer:"INDEX",explanation:"CREATE INDEX name ON table(column) creates index for faster queries. UNIQUE INDEX prevents duplicates too."},
    {id:6,question:"Complete check constraint:\n\nCREATE TABLE employees (\n  age INT _____ (age >= 18 AND age <= 65)\n);",options:["VALIDATE","ASSERT","CHECK","ENSURE"],answer:"CHECK",explanation:"CHECK constraint validates condition on insert/update. Throws error if condition false. Database-level validation."},
    {id:7,question:"Complete default value:\n\nCREATE TABLE orders (\n  status VARCHAR(20) _____ 'pending',\n  created_at TIMESTAMP _____ CURRENT_TIMESTAMP\n);",options:["DEFAULT","VALUE","INIT","SET"],answer:"DEFAULT",explanation:"DEFAULT sets value when column not specified in INSERT. status defaults to 'pending', created_at to current time."},
    {id:8,question:"Complete to modify column:\n\nALTER TABLE users\n_____ COLUMN email VARCHAR(255) NOT NULL;",options:["CHANGE","MODIFY","ALTER","UPDATE"],answer:"MODIFY",explanation:"ALTER TABLE ... MODIFY COLUMN changes column definition. MySQL uses MODIFY. PostgreSQL uses ALTER COLUMN. SQL Server uses ALTER COLUMN."},
    {id:9,question:"Complete ON DELETE behavior:\n\nFOREIGN KEY (userId)\nREFERENCES users(id)\nON DELETE _____;\n-- Set to NULL when parent deleted",options:["CASCADE","RESTRICT","SET NULL","NO ACTION"],answer:"SET NULL",explanation:"ON DELETE SET NULL: child userId set to NULL when parent deleted. Child row kept. CASCADE: child deleted. RESTRICT: prevents parent deletion."},
    {id:10,question:"Complete to drop table:\n\n_____ TABLE IF EXISTS temp_data;",options:["DELETE","REMOVE","DROP","CLEAR"],answer:"DROP",explanation:"DROP TABLE removes table and all data permanently. IF EXISTS prevents error if table doesn't exist. Cannot be rolled back in most DBs."},
  ]},
];